from google.rpc import status_pb2, code_pb2


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, authorized_tokens=None, required_headers=None):
        self.authorized_tokens = authorized_tokens or set()
        self.required_headers = required_headers or []
        
    def Check(self, request, context):
        print(f"Received authorization request")
        
        # Extract HTTP request attributes
        http_request = request.attributes.request.http
        headers = http_request.headers
        method = http_request.method
        path = http_request.path
        
        print(f"Method: {method}, Path: {path}")
        print(f"Headers: {headers}")
        
        # Check for authorization header
        auth_header = headers.get('authorization', '')
        
        # Check for custom headers
        custom_auth_token = headers.get('x-custom-auth-token', '')
        api_key = headers.get('x-api-key', '')
        
        # Authorization logic
        is_authorized = False
        denial_reason = ""
        
        # Check if required headers are present
        for required_header in self.required_headers:
            if required_header not in headers:
                denial_reason = f"Missing required header: {required_header}"
                break
        
        if not denial_reason:
            # Check authorization token
            if auth_header.startswith('Bearer '):
                token = auth_header[7:]
                if token in self.authorized_tokens:
                    is_authorized = True
                else:
                    denial_reason = "Invalid bearer token"
            elif custom_auth_token in self.authorized_tokens:
                is_authorized = True
            elif api_key in self.authorized_tokens:
                is_authorized = True
            else:
                denial_reason = "No valid authentication credentials provided"
        
        # Build response
        if is_authorized:
            # Allow the request
            response = external_auth_pb2.CheckResponse()
            response.status.code = code_pb2.OK
            
            # Add custom headers to the upstream request
            ok_response = external_auth_pb2.OkHttpResponse()
            header = ok_response.headers.add()
            header.header.key = "x-auth-user"
            header.header.value = "authenticated-user"
            
            header = ok_response.headers.add()
            header.header.key = "x-auth-time"
            header.header.value = str(int(time.time()))
            
            response.ok_http_response.CopyFrom(ok_response)
            
            print("Request authorized")
            return response
        else:
            # Deny the request
            response = external_auth_pb2.CheckResponse()
            response.status.code = code_pb2.PERMISSION_DENIED
            
            denied_response = external_auth_pb2.DeniedHttpResponse()
            denied_response.status.code = http_status_pb2.Forbidden
            denied_response.body = f"Access denied: {denial_reason}"
            
            # Add custom response headers
            header = denied_response.headers.add()
            header.header.key = "content-type"
            header.header.value = "text/plain"
            
            header = denied_response.headers.add()
            header.header.key = "x-auth-error"
            header.header.value = denial_reason
            
            response.denied_response.CopyFrom(denied_response)
            
            print(f"Request denied: {denial_reason}")
            return response


